mapper.select:
SELECT o.id, o.user_id, o.doctor_id, o.schedule_id, o.source_id, o.dept_name, o.work_date, o.work_time,
       o.order_status, o.create_time, o.update_time,
       d.doctor_name, d.title, d.avatar,
       u.nick_name as patient_name, u.username as patient_username
FROM hos_appointment_order o
LEFT JOIN hos_doctor d ON o.doctor_id = d.id
LEFT JOIN sys_user u ON o.user_id = u.id
WHERE o.deleted = 0

    AND o.user_id = #{params.userId}


    AND o.doctor_id = #{params.doctorId}


    AND o.dept_name LIKE CONCAT('%', #{params.deptName}, '%')


    AND o.order_status = #{params.orderStatus}


    AND o.work_date >= #{params.startDate}


    AND o.work_date <= #{params.endDate}

ORDER BY o.create_time DESC

SELECT COUNT(*) FROM hos_appointment_order
WHERE user_id = #{userId}
  AND doctor_id = #{doctorId}
  AND schedule_id = #{scheduleId}
  AND order_status = 1
  AND deleted = 0
